factory-callhome-key factory-callhome-cert
</#if> <#if http\-username?has_content || http\-password?has_content>
<#if http\-username?has_content> ${http\-username} </#if> <#if http\-password?has_content> ${http\-password} </#if>
</#if>
<#if tls\-version?has_content || cipher\-suite?has_content>
<#if tls\-version?has_content>
tlscmn:${tls\-version}
</#if> <#if cipher\-suite?has_content>
tlscsa:${cipher\-suite}
</#if>
</#if>
<#if private\-key\-algorithm?has_content>
ct:${private\-key\-algorithm}
</#if>
<#if subject\-distinguished\-name?has_content> ${subject\-distinguished\-name} </#if> <#if subject\-alternative\-name?has_content> ${subject\-alternative\-name} </#if> <#if auto\-fill\-duid\-attributes?has_content> ${auto\-fill\-duid\-attributes} </#if>
<#if restart\-connection\-after\-certificate\-update?has_content || key\-policy?has_content || (end\-entity\-certificate\-renew\-schedule\-type?has_content && end\-entity\-certificate\-renew\-schedule\-interval?has_content)>
<#if key\-policy=="reuse-existing-key"> enabled </#if> <#if key\-policy=="generate-new-key"> enabled </#if> <#if end\-entity\-certificate\-renew\-schedule\-type=="before-expiry"> ${end\-entity\-certificate\-renew\-schedule\-interval} </#if> <#if end\-entity\-certificate\-renew\-schedule\-type=="after-issue"> ${end\-entity\-certificate\-renew\-schedule\-interval} </#if> <#if restart\-connection\-after\-certificate\-update?has_content>
${restart\-connection\-after\-certificate\-update}
</#if>
